import React from 'react';

const ContactoPage = () => {
  return (
    <main style={styles.page}>
      <div style={styles.gridContainer}>
        {/* Área texto */}
        <section style={styles.textSection}>
          <h1 style={styles.title}>CONTACT US</h1>
          <p style={styles.paragraph}>
            If you have any questions or queries a member of staff will always be happy to help.
            Feel free to contact us by telephone or email and we will be sure to get back to you as soon as possible.
          </p>
        </section>

        {/* Área principal imagen o fondo */}
        <section style={styles.imageSection}>
          {/* Aquí puedes poner una imagen o simplemente dejar el fondo azul oscuro geométrico */}
        </section>

        {/* Área amarilla abajo izquierda */}
        <div style={styles.yellowBlock} />

        {/* Área verde abajo derecha */}
        <div style={styles.greenBlock} />
      </div>
    </main>
  );
};

const styles = {
  page: {
    minHeight: '100vh',
    fontFamily: "'Segoe UI', Tahoma, Geneva, Verdana, sans-serif",
    color: '#06232E', // color oscuro para texto
  },
  gridContainer: {
    display: 'grid',
    gridTemplateColumns: '1fr 2fr', // dos columnas, la segunda más ancha
    gridTemplateRows: '3fr 1fr', // filas, la de abajo es más corta
    gap: '0',
    height: '100vh',
    backgroundColor: '#F5EEDD', // beige claro de fondo general
  },
  textSection: {
    gridColumn: '1 / 2',
    gridRow: '1 / 2',
    padding: '6rem 4rem',
    backgroundColor: '#F5EEDD', // beige claro
    display: 'flex',
    flexDirection: 'column',
    justifyContent: 'center',
  },
  title: {
    fontSize: '3.5rem',
    fontWeight: '700',
    marginBottom: '1.5rem',
    color: '#06232E', // azul oscuro
  },
  paragraph: {
    fontSize: '1.25rem',
    lineHeight: '1.7',
    maxWidth: 400,
    color: '#06232E',
  },
  imageSection: {
    gridColumn: '2 / 3',
    gridRow: '1 / 3',
    backgroundColor: '#043D71', // azul oscuro
    clipPath: 'polygon(0 0, 100% 0%, 100% 100%, 0 75%)',
    // Aquí puedes poner una imagen de fondo si quieres:
    backgroundImage: 'url(/media/contactoPage/fondoGeom.png)', // pon ruta de imagen si tienes
    backgroundSize: 'cover',
    backgroundPosition: 'center',
  },
  yellowBlock: {
    gridColumn: '1 / 2',
    gridRow: '2 / 3',
    backgroundColor: '#DDB35A', // amarillo mostaza
  },
  greenBlock: {
    gridColumn: '2 / 3',
    gridRow: '2 / 3',
    backgroundColor: '#225C45', // verde oscuro
  },
};

export default ContactoPage;
